// @name         YMS Design Changes
// @namespace    https://phonetool.amazon.com/users/johjason
// @version      0.2.1.0
// @description  Various design changes to make the YMS Dashboard neater, easier and more functional.
// @author       johjason
// @downloadURL  https://axzile.corp.amazon.com/-/carthamus/download_script/yms-design-changes.user.js
// @updateURL    https://axzile.corp.amazon.com/-/carthamus/download_script/yms-design-changes.user.js
// @match        https://trans-logistics.amazon.com/yms/shipclerk/*
// @match        https://trans-logistics-eu.amazon.com/yms/shipclerk/*
// @icon         https://images-na.ssl-images-amazon.com/images/G/01/TransCentral/images/favicon.ico
// @resource     REMOTE_CSS https://drive.corp.amazon.com/view/TOM%20Utilities/TamperMonkey/YMS%20Design%20Changes/newstyle.css?ver=1.5
// @resource     LIGHT_CSS https://drive.corp.amazon.com/view/TOM%20Utilities/TamperMonkey/YMS%20Design%20Changes/newstyle.css?ver=1.5
// @resource     DARK_CSS https://drive.corp.amazon.com/view/TOM%20Utilities/TamperMonkey/YMS%20Design%20Changes/newstyle.dark.css?ver=1.5
// @grant        GM_getResourceText
// @grant        GM_addStyle
// @require      https://code.jquery.com/jquery-3.7.0.min.js
// @run-at       document-end
// ==/UserScript==

/* globals $ */

(function (window, document) {

    window.onload = init;

    GM_addStyle(GM_getResourceText("REMOTE_CSS"));

    // Dodanie stylów FUI dla przycisku kopiowania
    GM_addStyle(`
      .oxy-copy-btn {
        background: transparent;
        color: #f36c00;
        border: 1px solid #555555;
        border-radius: 0 !important;
        padding: 4px 8px;
        font-family: 'JetBrains Mono', 'Roboto Mono', monospace;
        font-size: 10px;
        text-transform: uppercase;
        cursor: pointer;
        user-select: none;
        transition: all 0.3s ease-in-out;

        &:hover {
          background: #f36c00;
          color: #FFFFFF;
          border-color: #f36c00;
        }

        &:active {
          opacity: 0.8;
        }
      }

      #trailerdashboard .empty,
      #trailerdashboard .emptyalert {
        display: inline-block;
        min-width: 1.5em;
      }
      #trailerdashboard .emptyalert {
        color: #c00;
        font-weight: bold;
      }
    `);

    function init() {

        'use strict';
        document.getElementById('mainContainer').insertAdjacentHTML('beforebegin', `
                <div id="custom-options-container">
                    <h3 id="dark-mode-label">
                        <t>Dark Mode:</t>
                    </h3>
                    <div id="dark-mode-switch">
                        <input id="dark-mode-toggle" type="checkbox">
                        <label for="dark-mode-toggle"></label>
                    </div>
                    <h3 id="filterTrailer-label">
                        <t>Tagged Trailers:</t>
                    </h3>
                    <div>
                        <input id="filterTrailer-toggle" type="checkbox">
                        <label for="filterTrailer"></label>
                    </div>
                </div>
          ` );
        document.getElementById('dark-mode-toggle').addEventListener('change', function () {
            // We're going to play the day time, night time game
            if (document.getElementById('dark-mode-toggle').checked) {
                // Night time
                GM_addStyle(GM_getResourceText("DARK_CSS"));
            } else {
                // Day time
                GM_addStyle(GM_getResourceText("LIGHT_CSS"));
            }
        });
        document.getElementById('filterTrailer-toggle').addEventListener('change', function () {
            // We're going to do an action once the checkbox for tagged trailers is checked
            if (document.getElementById('filterTrailer-toggle').checked) {
                $("#ship-clerk-dashboard-table tbody tr").show();

                // Keeping the old way in just in case tech team changes the way red/yellow tagged trailers are displayed - var targChecked = ".masterYardLP td:nth-child(7):not('.col8.yardAsset-unavailable')";
                // Looking for specific classes that are displaying the red and yellow tag on YMS and only in the div containing flex-container and row, using this as a filter
                var targChecked = $(".flex-container.row").filter(function () { return $(this).children(".yard-asset-yellow,.yard-asset-red").length == 0; });
                var targCheckedEmpty = $(".masterYardLP td:nth-child(2):not('[class^=col2]')");
                // Combining the above two elements so that we essentially have 2 filters - this is for when the checkbox is CHECKED
                var targCheckedCombined = targChecked.add(targCheckedEmpty);

                // Using our filters above to hide table rows, but ignoring tables that are children
                $(targCheckedCombined).closest('tr').not("tr tr").hide();
            } else {
                // We're going to do the UNDO actions once the checkbox for tagged trailers is UNCHECKED
                $("#ship-clerk-dashboard-table tbody tr").show();

                // Keeping the old way in just in case tech team changes the way red/yellow tagged trailers are displayed - var targUnchecked = ".masterYardLP td:nth-child(7):not('.col8.yardAsset-unavailable')";
                var targUnchecked = $(".flex-container.row").filter(function () { return $(this).children(".yard-asset-yellow,.yard-asset-red").length == 0; });
                var targUncheckedEmpty = $(".masterYardLP td:nth-child(2):not('[class^=col2]')");
                // Combining the above two elements so that we essentially have 2 filters - this is for when the checkbox is UNCHECKED
                var targUncheckedCombined = targUnchecked.add(targUncheckedEmpty);

                // Using our filters above to show table rows again, but ignoring tables that are children
                $(targUncheckedCombined).closest('tr').not("tr tr").show();
            }
        });

        if (window.location.href.indexOf("shipclerk/#/yard") > -1) {
            document.styleSheets[0].insertRule('.note-present-icon {flex-shrink: 0;}');
            document.getElementById('mainContainer').insertAdjacentHTML('beforebegin', `
               <div id="trailerdashboard">
                       <h2 style="text-align: center;"><div id="emptyazng">AZNG Empties in PS: <span id="val-emptyazng" class="empty">0</span></div></h2>
                       <h2 style="text-align: center;"><div id="dockempty">AZNG Empties on DD: <span id="val-dockempty" class="empty">0</span></div></h2>
                       <h2 style="text-align: center;"><div id="taggedazng">Tagged AZNG Trailers: <span id="val-taggedazng" class="empty">0</span></div></h2>
                       <h2 style="text-align: center;"><div id="loadedAZNG">Loaded AZNG w/ No VRID: <span id="val-loadedazng" class="empty">0</span></div></h2>
                       <h2 style="text-align: center;"><div id="ddemptydiv">Open Dock Doors: <span id="val-ddempty" class="empty">0</span></div></h2>
                       <h2 style="text-align: center;"><div id="tdrout">Doors TDR'd Out: <span id="val-tdrout" class="empty">0</span></div></h2>
                       <h2 style="text-align: center;"><div id="psemptydiv">Open Slips: <span id="val-psempty" class="empty">0</span></div></h2>
                       <h2 style="text-align: center;"><div id="nonazng">OnSite Non AZNG Emptys: <span id="val-nonazng" class="empty">0</span></div></h2>
                       <h2 style="text-align: center;"><div id="tractors">Tractors: <span id="val-tractors" class="empty">0</span></div></h2>
                       <h2 style="text-align: center;"><div id="nicarts">NICART Loads: <span id="val-nicarts" class="empty">0</span></div></h2>
                   </div>
          ` );
            function emptyAZNG() {
                var tagged = 0;
                var nicarts = 0;
                var nonazng = 0;
                var nonoff = 0;
                var tractorsYard = $('.yard-asset-icon-TRACTOR').length;
                var noTDR = $('.NoTDR').length;
                var psEmpty = $("tr.empty-location > td.col1 > div.location-type-ParkingLocation").length;
                var ddEmpty = $("tr.empty-location > td.col1 > div.location-type-ProcessingLocation").length;
                var emptyAZNGinPS = 0;
                var emptyAZNGinDD = 0;
                var empty3PinPS = 0
                var loadedAZNGnoVRID = 0;
                $('tr.ng-scope').each(function () {
                    if ($(this).find('.location-type-ParkingLocation').length > 0 && $(this).find('.yardasset-empty').length > 0 && $(this).find('.ownerOperatorCodeGroup :contains("AZNG")').length > 0) {
                        emptyAZNGinPS = emptyAZNGinPS + 1;
                    }
                    if ($(this).find('.location-type-ProcessingLocation').length > 0 && $(this).find('.yardasset-empty').length > 0 && $(this).find('.ownerOperatorCodeGroup :contains("AZNG")').length > 0) {
                        emptyAZNGinDD = emptyAZNGinDD + 1;
                    }
                    if ($(this).find('.location-type-ParkingLocation').length > 0 && $(this).find('.yardasset-empty').length > 0 && $(this).find('.ownerOperatorCodeGroup :not(:contains("AZNG"))').length > 0) {
                        empty3PinPS = empty3PinPS + 1;
                    }
                });
                $('tr.ng-scope').each(function () {
                    if ($(this).find('.yardAsset-unavailable').length > 0 && $(this).find('.ownerOperatorCodeGroup :contains("AZNG")').length > 0) {
                        tagged = tagged + 1;
                    }
                });
                var wholerows = document.querySelectorAll('tr.ng-scope');
                Array.prototype.forEach.call(wholerows, function (col) {
                    if (col.innerHTML.match(/highlight yardasset-full"/) && col.innerHTML.match(/AZNG/) && !col.innerHTML.match(/vrid/)) {
                        loadedAZNGnoVRID = loadedAZNGnoVRID + 1;
                    } else if (col.innerHTML.match(/highlight yardasset-empty"/) && !col.innerHTML.match(/TRACTOR highlight yardasset-empty"/) && !col.innerHTML.match(/AZNG/) && !col.innerHTML.match(/vrid/)) {
                        nonazng = nonazng + 1;
                    } else if (col.innerHTML.match(/highlight yardasset-empty"/) && !col.innerHTML.match(/AZNG/) && !col.innerHTML.match(/vrid/) && !col.innerHTML.match(/LDLB/) && !col.innerHTML.match(/BSPC/) && !col.innerHTML.match(/BRDZ/) && !col.innerHTML.match(/DUMMY/) && (!col.innerHTML.match(/class="col1 /) || col.innerHTML.match(/OSY/))) {
                        nonoff = nonoff + 1;
                    }
                    if ((col.innerHTML.match(/TransfersEmptyCar/) || col.innerHTML.match(/NICARTS/i)) && !col.innerHTML.match(/yard-asset-icon-TRACTOR/)) {
                        nicarts = nicarts + 1;
                    }
                });
                var tagtag = "empty";
                var tag = "empty";
                if (psEmpty < 5) {
                    tag = "emptyalert";
                } else {
                    tag = "empty";
                }
                if (tagged > 2) {
                    tagtag = "emptyalert";
                } else {
                    tagtag = "empty";
                }
                var my_div = document.getElementById('emptyazng');
                my_div.innerHTML = 'AZNG Empties in PS: <span id="val-emptyazng" class="' + tag + '">' + emptyAZNGinPS + '</span>';
                var my_div2 = document.getElementById('taggedazng');
                my_div2.innerHTML = 'Tagged AZNG Trailers: <span id="val-taggedazng" class="' + tagtag + '">' + tagged + '</span>';
                var my_div3 = document.getElementById('dockempty');
                my_div3.innerHTML = 'AZNG Empties on DD: <span id="val-dockempty" class="empty">' + emptyAZNGinDD + '</span>';
                var loadedAZNGdiv = document.getElementById('loadedAZNG');
                loadedAZNGdiv.innerHTML = 'Loaded AZNG w/ No VRID: <span id="val-loadedazng" class="empty">' + loadedAZNGnoVRID + '</span>';
                var my_div4 = document.getElementById('nicarts');
                my_div4.innerHTML = 'NICART Loads: <span id="val-nicarts" class="empty">' + nicarts + '</span>';
                var my_div5 = document.getElementById('tractors');
                my_div5.innerHTML = 'Tractors: <span id="val-tractors" class="empty">' + tractorsYard + '</span>';
                var nonazngdiv = document.getElementById('nonazng');
                nonazngdiv.innerHTML = 'OnSite Non AZNG emptys: <span id="val-nonazng" class="empty">' + empty3PinPS + '</span>';
                var emptypsdiv = document.getElementById('psemptydiv');
                emptypsdiv.innerHTML = 'Open Slips: <span id="val-psempty" class="empty">' + psEmpty + '</span>';
                var ddemptydiv = document.getElementById('ddemptydiv');
                ddemptydiv.innerHTML = 'Open Dock Doors: <span id="val-ddempty" class="empty">' + ddEmpty + '</span>';
                var tdrdoutdiv = document.getElementById('tdrout');
                tdrdoutdiv.innerHTML = 'Doors TDR\'d Out: <span id="val-tdrout" class="empty">' + noTDR + '</span>';

            }
            setInterval(emptyAZNG, 60000); // Poll for empties update 60 seconds
            setTimeout(emptyAZNG, 10000); // Initial update after 10 seconds
        }
        // ------------------------------------------------------------------------------------------------------------
        // Poprawiona funkcja dodająca przyciski kopiowania numerów rejestracyjnych
        function addLicensePlateCopyButtons() {
            $("span[ng-if='yardAsset.vehicleNumber'], span[ng-if='yardAsset.licensePlateIdentifier && yardAsset.licensePlateIdentifier.registrationIdentifier']").each(function () {
                var numberHtml = $(this).html() || "";
                var number = numberHtml.split("<br>")[0].trim();

                if ($(this).parent().parent().find("button.oxy-copy-btn").length < 1) {
                    var copyButton = $("<button>", {
                        class: "oxy-copy-btn superuserTooltip",
                        title: "COPY TO CLIPBOARD",
                        text: "COPY"
                    }).click(function (e) {
                        e.preventDefault();
                        navigator.clipboard.writeText(number.split(" ")[0]).then(() => {
                            let ref = $(this);
                            ref.text("COPIED!");

                            setTimeout(function () {
                                ref.text("COPY");
                            }, 2000);
                        }).catch(err => {
                            console.error('Błąd kopiowania:', err);
                        });
                    });

                    $(this).parent().parent()
                        .append($("<br>"))
                        .append(copyButton);
                }
            });
        }

        // Funkcja sprawdzająca i dodająca przyciski
        function checkAndAddButtons() {
            if ($("#noteTextArea").is(":visible")) {
                if ($("#sealStatusDiv").length === 0 && typeof addSealStatusButtons === "function") {
                    addSealStatusButtons();
                }
                if ($("#pageToggleButton").length === 0 && typeof createToggleButton === "function") {
                    createToggleButton();
                }

                $("#pageToggleButton").show();

                if ($("#pageToggleButton").text() === "Next Page") {
                    $("#sealStatusDiv").show();
                    if ($("#page2Content").length > 0) {
                        $("#page2Content").hide();
                    }
                } else {
                    $("#sealStatusDiv").hide();
                    if ($("#page2Content").length === 0 && typeof createPage2 === "function") {
                        createPage2();
                    }
                    $("#page2Content").show();
                }
            } else {
                $("#sealStatusDiv, #page2Content, #pageToggleButton").hide();
            }
            addLicensePlateCopyButtons();
        }

        // Zapewnienie, że przyciski pojawią się w dynamicznie ładowanej aplikacji (Angular)
        setInterval(function () {
            checkAndAddButtons();
        }, 1500);

        // ------------------------------------------------------------------------------------------
        // Variable to track the visibility of the div with id "top-section"
        var isTopSectionVisible = true;
        var toggleButton;

        // Function to toggle changes on various elements
        function toggleChanges() {
            var topbarData = document.getElementById('topbarData');
            var searchResults = document.querySelector('.ship-clerk-search-results');
            var tcpWidget = document.querySelector('.tcp-widget');
            var scrollTable = document.querySelector('.scrolltable');
            var topSection = document.getElementById('top-section');

            if (topbarData && searchResults && tcpWidget && scrollTable && topSection) {
                // Toggle the changes for topbarData
                if (topbarData.style.visibility === 'hidden') {
                    topbarData.style.visibility = 'visible';
                    topbarData.style.opacity = '1';
                    topbarData.style.zIndex = '1';
                    toggleButton.innerHTML = 'Collapse';
                } else {
                    topbarData.style.visibility = 'hidden';
                    topbarData.style.opacity = '0';
                    topbarData.style.zIndex = '-999';
                    toggleButton.innerHTML = 'Grow';
                }

                // Toggle the changes for searchResults
                if (searchResults.style.marginTop === '-179px') {
                    searchResults.style.marginTop = '0';
                    searchResults.style.zIndex = 'auto';
                } else {
                    searchResults.style.marginTop = '-179px';
                    searchResults.style.zIndex = '999';
                }

                // Toggle the changes for tcpWidget
                if (tcpWidget.style.visibility === 'collapse') {
                    tcpWidget.style.visibility = 'visible';
                } else {
                    tcpWidget.style.visibility = 'collapse';
                }

                // Toggle the changes for scrollTable
                if (scrollTable.style.height === '150%') {
                    scrollTable.style.height = '100%';
                } else {
                    scrollTable.style.height = '150%';
                }

                // Toggle the visibility of topSection
                if (isTopSectionVisible) {
                    topSection.style.display = 'none';
                    isTopSectionVisible = false;
                } else {
                    topSection.style.display = '-webkit-flex';
                    isTopSectionVisible = true;
                }
            }
        }

        // Function to add the button after a 5-second delay
        // We must add the 5-second delay to account for the internal page refresh after the browser is done loading.
        function addToggleButton() {
            // Find the div with id "clearButtonGroup"
            var clearButtonGroup = document.getElementById('clearButtonGroup');
            // Check if the div is found
            if (clearButtonGroup) {
                // Set "clearButtonGroup" as a flex container with justifyContent center to allow appeneded button to align horizontal
                clearButtonGroup.style.display = 'flex';
                clearButtonGroup.style.justifyContent = 'center';
                clearButtonGroup.style.alignItems = 'center'; // Optionally align items at the center

                // Create a new button element
                toggleButton = document.createElement('button');
                toggleButton.innerHTML = 'Collapse';
                toggleButton.style.cursor = 'pointer';

                // Add click event to toggle changes on various elements
                toggleButton.addEventListener('click', toggleChanges);

                // Append the button to the "clearButtonGroup" div
                clearButtonGroup.appendChild(toggleButton);
            }
        }

        // Wait for a 5-second delay after the page is fully loaded
        setTimeout(addToggleButton, 5000);
    };
})(window, document);
"}

